// ============================================
// Parse Evolution API inbound message
// Filters: own messages, groups, unsupported types
// ============================================

const body = $input.first().json.body || $input.first().json;

// Evolution API sends messages.upsert events
const messages = body.data?.messages || body.messages || [];
const message = messages[0] || body.data || body;

const key = message.key || {};
const remoteJid = key.remoteJid || message.remoteJid || '';
const fromMe = key.fromMe || false;
const wamid = key.id || message.id || '';
const pushName = message.pushName || '';
const instanceName = body.instance || body.instanceName || '';

// Ignore own messages
if (fromMe) {
  return [{ json: { ignore: true, reason: 'from_me' } }];
}

// Ignore group messages
if (remoteJid.includes('@g.us')) {
  return [{ json: { ignore: true, reason: 'group_message' } }];
}

// Ignore status broadcasts
if (remoteJid === 'status@broadcast') {
  return [{ json: { ignore: true, reason: 'status_broadcast' } }];
}

// Extract message content
const msgContent = message.message || {};
let messageContent = '';
let messageType = 'unsupported';

if (msgContent.conversation) {
  messageContent = msgContent.conversation;
  messageType = 'text';
} else if (msgContent.extendedTextMessage?.text) {
  messageContent = msgContent.extendedTextMessage.text;
  messageType = 'text';
} else if (msgContent.imageMessage?.caption) {
  messageContent = msgContent.imageMessage.caption;
  messageType = 'image';
} else if (msgContent.audioMessage) {
  messageContent = '[Áudio]';
  messageType = 'audio';
} else if (msgContent.documentMessage?.caption) {
  messageContent = msgContent.documentMessage.caption;
  messageType = 'document';
}

// Ignore unsupported message types without text content
if (!messageContent) {
  return [{ json: { ignore: true, reason: 'no_text_content', messageType } }];
}

return [{
  json: {
    ignore: false,
    remoteJid,
    pushName,
    wamid,
    messageContent,
    messageType,
    instanceName,
    phone: remoteJid.split('@')[0]
  }
}];

// ============================================
// Generate available slots for scheduling
// 3 próximos dias úteis, horários 9h-17h, de hora em hora
// Filtra slots já ocupados
// Retorna os 3 primeiros disponíveis
// ============================================

const msgData = $('Parse Evolution Payload').first().json;
const clinicData = $('Buscar Config Clínica').first().json;

const clinicId = clinicData?.clinic_id || clinicData?.clinicId || clinicData?.clinicid || null;

// Generate candidate slots: next 3 business days, 9-17h
const slots = [];
const now = new Date();
let daysAdded = 0;
let checkDate = new Date(now);
checkDate.setDate(checkDate.getDate() + 1); // Start from tomorrow

while (daysAdded < 3) {
  const dow = checkDate.getDay();
  // Skip weekends
  if (dow !== 0 && dow !== 6) {
    for (let h = 9; h <= 17; h++) {
      const slot = new Date(checkDate);
      slot.setHours(h, 0, 0, 0);
      const y = slot.getFullYear();
      const m = String(slot.getMonth() + 1).padStart(2, '0');
      const d = String(slot.getDate()).padStart(2, '0');
      const hh = String(slot.getHours()).padStart(2, '0');
      slots.push(`${y}-${m}-${d} ${hh}:00`);
    }
    daysAdded++;
  }
  checkDate.setDate(checkDate.getDate() + 1);
}

// Return first 3 available slots (no appointment filtering in this version)
const availableSlots = slots.slice(0, 3);

return [{
  json: {
    ...msgData,
    clinicId,
    availableSlots
  }
}];

