// Parse Sofia API response
const response = $input.first().json;
const body = response.body || response;

return [{
  json: {
    responseMessage: body.response_message || '',
    shouldSend: body.should_send !== false,
    agentName: body.agent_name || 'Sofia',
    conversationStage: body.conversation_stage || 'active',
    sessionId: body.session_id || '',
    requiresHuman: body.requires_human === true,
    appointmentCreated: body.appointment_created || null,
    processingTimeMs: body.processing_time_ms || 0
  }
}];

